    public int getLsbIndex(byte[] state, int garlic) {
        int bytes = garlic + 7 >>> 3;
        int shiftBits = (8 - garlic % 8) % 8;
        int mask = 255 >>> shiftBits;
        int len = state.length;
        int first = len - bytes;
        int val = 0;
        val = state[first] & mask;
        int i = first + 1;
        while (i < len) {
            val = val << 8 | state[i] & 0xFF;
            ++i;
        }
        return val;
    }


